        new ClayPlaced { position = new Vector3( 40f, 0f,  20f), scale = new Vector3(3f, 3f, 8f) },

        // Central frost-stone dividers
        new ClayPlaced { position = new Vector3( 10f, 0f, -10f), scale = new Vector3(4f, 2.5f, 10f) },
        new ClayPlaced { position = new Vector3(-10f, 0f,  10f), scale = new Vector3(4f, 2.5f, 10f) },

