        new ClayPlaced { position = new Vector3( 90f, 0f,  30f), scale = new Vector3(5f, 2.5f, 3f) },

        // Decorative lane barriers for non-linear paths
        new ClayPlaced { position = new Vector3(-110f, 0f, 60f), scale = new Vector3(4f, 2.2f, 8f) },
        new ClayPlaced { position = new Vector3( 110f, 0f, -60f), scale = new Vector3(4f, 2.2f, 8f) },
